package cache

import (
	"strings"
	"testing"
	"time"
)

func TestPathUsesFullSHA256Digest(t *testing.T) {
	t.Parallel()

	store := New(t.TempDir(), time.Minute)
	path := store.path("GET /protocols")

	if !strings.HasSuffix(path, ".json") {
		t.Fatalf("cache path %q missing .json suffix", path)
	}
	name := path[strings.LastIndex(path, "/")+1 : len(path)-len(".json")]
	if got, want := len(name), 64; got != want {
		t.Fatalf("cache digest length = %d, want full SHA256 hex length %d", got, want)
	}
}
